import{_ as a,c as i,o as l,a1 as r}from"./chunks/framework.DILC4Csi.js";const c=JSON.parse('{"title":"고급: 파이프라인과 내부 메커니즘 | AI App Factory 튜토리얼","description":"AI App Factory의 7단계 파이프라인, Sisyphus 스케줄러, 권한 보안 메커니즘, 실패 처리 전략을 심층적으로 알아보세요. 컨텍스트 최적화와 고급 설정 기법을 익히세요.","frontmatter":{"title":"고급: 파이프라인과 내부 메커니즘 | AI App Factory 튜토리얼","sidebarTitle":"고급: 파이프라인","subtitle":"고급: 파이프라인과 내부 메커니즘","description":"AI App Factory의 7단계 파이프라인, Sisyphus 스케줄러, 권한 보안 메커니즘, 실패 처리 전략을 심층적으로 알아보세요. 컨텍스트 최적화와 고급 설정 기법을 익히세요.","tags":["파이프라인","스케줄러","권한 보안","실패 처리"],"prerequisite":["start-pipeline-overview"],"order":80},"headers":[],"relativePath":"ko/hyz1992/agent-app-factory/advanced/index.md","filePath":"ko/hyz1992/agent-app-factory/advanced/index.md"}'),e={name:"ko/hyz1992/agent-app-factory/advanced/index.md"};function o(s,t,n,p,d,h){return l(),i("div",null,[...t[0]||(t[0]=[r('<h1 id="고급-파이프라인과-내부-메커니즘" tabindex="-1">고급: 파이프라인과 내부 메커니즘 <a class="header-anchor" href="#고급-파이프라인과-내부-메커니즘" aria-label="Permalink to &quot;고급: 파이프라인과 내부 메커니즘&quot;">​</a></h1><p>이 챕터에서는 AI App Factory의 핵심 메커니즘과 고급 기능을 심층적으로 설명합니다. 7단계 파이프라인의 상세한 작동 원리, Sisyphus 스케줄러의 스케줄링 전략, 권한과 보안 메커니즘, 실패 처리 전략, 그리고 컨텍스트 최적화를 통해 Token 비용을 절약하는 방법을 다룹니다.</p><div class="warning custom-block"><p class="custom-block-title">전제 조건</p><p>이 챕터를 학습하기 전에 다음 내용을 완료했는지 확인하세요:</p><ul><li><a href="./../../start/getting-started/">빠른 시작</a> 및 <a href="./../../start/installation/">설치 설정</a></li><li><a href="./../../start/pipeline-overview/">7단계 파이프라인 개요</a></li><li><a href="./../../platforms/claude-code/">플랫폼 통합</a> 설정</li></ul></div><h2 id="챕터-내용" tabindex="-1">챕터 내용 <a class="header-anchor" href="#챕터-내용" aria-label="Permalink to &quot;챕터 내용&quot;">​</a></h2><p>이 챕터는 다음 주제를 포함합니다:</p><h3 id="_7단계-파이프라인-상세-설명" tabindex="-1">7단계 파이프라인 상세 설명 <a class="header-anchor" href="#_7단계-파이프라인-상세-설명" aria-label="Permalink to &quot;7단계 파이프라인 상세 설명&quot;">​</a></h3><ul><li><p><strong><a href="./stage-bootstrap/">단계 1: Bootstrap - 제품 아이디어 구조화</a></strong></p><ul><li>모호한 제품 아이디어를 구조화된 문서로 변환하는 방법 학습</li><li>Bootstrap Agent의 입력 출력 형식 이해</li></ul></li><li><p><strong><a href="./stage-prd/">단계 2: PRD - 제품 요구사항 문서 생성</a></strong></p><ul><li>사용자 스토리, 기능 목록, 비목표를 포함한 MVP 수준 PRD 생성</li><li>요구사항 분해와 우선순위 정렬 기법 익히기</li></ul></li><li><p><strong><a href="./stage-ui/">단계 3: UI - 인터페이스와 프로토타입 설계</a></strong></p><ul><li>ui-ux-pro-max 스킬을 사용하여 UI 구조와 미리보기 가능한 프로토타입 설계</li><li>인터페이스 설계 프로세스와 모범 사례 이해</li></ul></li><li><p><strong><a href="./stage-tech/">단계 4: Tech - 기술 아키텍처 설계</a></strong></p><ul><li>최소한의 실행 가능한 기술 아키텍처와 Prisma 데이터 모델 설계</li><li>기술 선정과 아키텍처 설계 원칙 익히기</li></ul></li><li><p><strong><a href="./stage-code/">단계 5: Code - 실행 가능한 코드 생성</a></strong></p><ul><li>UI Schema와 Tech 설계를 기반으로 프론트엔드/백엔드 코드, 테스트, 설정 생성</li><li>코드 생성 프로세스와 템플릿 시스템 이해</li></ul></li><li><p><strong><a href="./stage-validation/">단계 6: Validation - 코드 품질 검증</a></strong></p><ul><li>의존성 설치, 타입 체크, Prisma 스키마, 코드 품질 검증</li><li>자동화된 품질 검사 프로세스 익히기</li></ul></li><li><p><strong><a href="./stage-preview/">단계 7: Preview - 배포 가이드 생성</a></strong></p><ul><li>완전한 실행 설명 문서와 배포 설정 생성</li><li>CI/CD 통합과 Git Hooks 설정 학습</li></ul></li></ul><h3 id="내부-메커니즘" tabindex="-1">내부 메커니즘 <a class="header-anchor" href="#내부-메커니즘" aria-label="Permalink to &quot;내부 메커니즘&quot;">​</a></h3><ul><li><p><strong><a href="./orchestrator/">Sisyphus 스케줄러 상세 설명</a></strong></p><ul><li>스케줄러가 파이프라인을 조정하고, 상태를 관리하며, 권한 검사를 실행하는 방법 이해</li><li>스케줄링 전략과 상태 머신 원리 익히기</li></ul></li><li><p><strong><a href="./context-optimization/">컨텍스트 최적화: 분할 세션 실행</a></strong></p><ul><li><code>factory continue</code> 명령어를 사용하여 Token을 절약하는 방법 학습</li><li>각 단계에서 새 세션을 생성하는 모범 사례 익히기</li></ul></li><li><p><strong><a href="./security-permissions/">권한과 보안 메커니즘</a></strong></p><ul><li>능력 경계 매트릭스, 권한 초과 처리, 보안 검사 메커니즘 이해</li><li>보안 설정과 권한 관리 익히기</li></ul></li><li><p><strong><a href="./failure-handling/">실패 처리와 롤백</a></strong></p><ul><li>실패 식별, 재시도 메커니즘, 롤백 전략, 수동 개입 프로세스 학습</li><li>장애 진단과 복구 기법 익히기</li></ul></li></ul><h2 id="학습-경로-권장사항" tabindex="-1">학습 경로 권장사항 <a class="header-anchor" href="#학습-경로-권장사항" aria-label="Permalink to &quot;학습 경로 권장사항&quot;">​</a></h2><h3 id="권장-학습-순서" tabindex="-1">권장 학습 순서 <a class="header-anchor" href="#권장-학습-순서" aria-label="Permalink to &quot;권장 학습 순서&quot;">​</a></h3><ol><li><p><strong>먼저 7단계 파이프라인 완료하기</strong> (순서대로)</p><ul><li>Bootstrap → PRD → UI → Tech → Code → Validation → Preview</li><li>각 단계는 명확한 입력 출력이 있으며, 순서대로 학습하면 완전한 이해를 구축할 수 있습니다</li></ul></li><li><p><strong>그 다음 스케줄러와 컨텍스트 최적화 학습</strong></p><ul><li>Sisyphus가 이 7개 단계를 어떻게 조정하는지 이해</li><li>Token 비용을 절약하기 위한 컨텍스트 최적화 방법 학습</li></ul></li><li><p><strong>마지막으로 보안과 실패 처리 학습</strong></p><ul><li>권한 경계와 보안 메커니즘 익히기</li><li>실패 시나리오와 대응 전략 이해</li></ul></li></ol><h3 id="다른-역할의-학습-중점" tabindex="-1">다른 역할의 학습 중점 <a class="header-anchor" href="#다른-역할의-학습-중점" aria-label="Permalink to &quot;다른 역할의 학습 중점&quot;">​</a></h3><table tabindex="0"><thead><tr><th>역할</th><th>중점 학습 챕터</th></tr></thead><tbody><tr><td><strong>개발자</strong></td><td>Code, Validation, Tech, Orchestrator</td></tr><tr><td><strong>제품 관리자</strong></td><td>Bootstrap, PRD, UI, Preview</td></tr><tr><td><strong>기술 책임자</strong></td><td>Tech, Code, Security, Failure Handling</td></tr><tr><td><strong>DevOps 엔지니어</strong></td><td>Validation, Preview, Context Optimization</td></tr></tbody></table><h2 id="다음-단계" tabindex="-1">다음 단계 <a class="header-anchor" href="#다음-단계" aria-label="Permalink to &quot;다음 단계&quot;">​</a></h2><p>이 챕터를 완료한 후 다음 내용을 계속 학습할 수 있습니다:</p><ul><li><strong><a href="./../../faq/troubleshooting/">FAQ와 문제 해결</a></strong> - 실제 사용 중 문제 해결</li><li><strong><a href="./../../faq/best-practices/">모범 사례</a></strong> - Factory를 효율적으로 사용하는 기법 익히기</li><li><strong><a href="./../../appendix/cli-commands/">CLI 명령어 참조</a></strong> - 완전한 명령어 목록 확인</li><li><strong><a href="./../../appendix/code-standards/">코드 표준</a></strong> - 생성된 코드가 따라야 할 표준 이해</li></ul><hr><p>💡 <strong>팁</strong>: 사용 중 문제가 발생하면 먼저 <a href="./../../faq/troubleshooting/">FAQ와 문제 해결</a> 챕터를 확인하세요.</p>',19)])])}const g=a(e,[["render",o]]);export{c as __pageData,g as default};
